1	#pragma once
2	/**
3	 * @file
4	 * @brief This file defines the RouteTree and RouteTreeNode, used to keep partial or full routing
5	 * state and timing information for a net.
6	 *
7	 * Overview
8	 * ========
9	 * A RouteTree holds a root RouteTreeNode and exposes top level operations on the tree, such as
10	 * RouteTree::update_from_heap() and RouteTree::prune().
11	 *
12	 * Routing itself is not done using this representation. The route tree is pushed to the heap with
13	 * ConnectionRouterInterface::timing_driven_route_connection_from_route_tree() and the newly found path
14	 * is committed via RouteTree::update_from_heap(). The timing data is updated with RouteTree::reload_timing() where required.
15	 *
16	 * Each net in the netlist given to the router has a single RouteTree, which is kept in RoutingContext::route_trees.
17	 *
18	 * Usage
19	 * =====
20	 *
21	 * A RouteTree either requires a RRNodeId or a ParentNetId (as the source node) to construct:
22	 *
23	 *      RouteTree tree(inet);
24	 *      // ...
25	 *
26	 * RouteTrees cannot be manually updated. The only way to extend them is to first route a connection and then update from the resulting heap.
27	 *
28	 *      std::tie(found_path, cheapest) = router.timing_driven_route_connection_from_route_tree(tree.root(), ...);
29	 *      if (found_path)
30	 *           std::tie(std::ignore, rt_node_of_sink) = tree.update_from_heap(&cheapest, ...);
31	 *
32	 * Congested paths in a tree can be pruned using RouteTree::prune(). This is done between iterations to keep only the legally routed section.
33	 * Note that updates to a tree require an update to the global occupancy state via pathfinder_update_cost_from_route_tree().
34	 * RouteTree::prune() depends on this global data to find congestions, so the flow to prune a tree is somewhat convoluted:
35	 *
36	 *      RouteTree tree2 = tree;
37	 *      // Prune the copy (using congestion data before subtraction)
38	 *      vtr::optional<RouteTree&> pruned_tree2 = tree2.prune(connections_inf);
39	 *
40	 *      // Subtract congestion using the non-pruned original
41	 *      pathfinder_update_cost_from_route_tree(tree.root(), -1);
42	 *
43	 *      if (pruned_tree2) {  // Partially pruned
44	 *          // Add back congestion for the pruned route tree
45	 *          pathfinder_update_cost_from_route_tree(pruned_tree2.value().root(), 1);
46	 *          ...
47	 *      } else {  // Fully destroyed
48	 *          ...
49	 *
50	 * Most usage of RouteTree outside of the router requires iterating through existing routing. Both RouteTree and RouteTreeNode exposes functions to
51	 * traverse the tree.
52	 *
53	 * To iterate over all nodes in the tree:
54	 *
55	 *      RouteTree& tree = route_ctx.route_trees[inet].value();
56	 *
57	 *      for (auto& node: tree.all_nodes()) {
58	 *          // ...
59	 *      }
60	 *
61	 * This will walk the tree in depth-first order. Breadth-first traversal would require recursion:
62	 *
63	 *      const RouteTreeNode& root = tree.root();
64	 *
65	 *      for (auto& child: root.child_nodes()) {
66	 *          // recurse...
67	 *      }
68	 *
69	 * To walk a node's subtree in depth-first order:
70	 *
71	 *      for (auto& node: root.all_nodes()) {  // doesn't include root!
72	 *          // ...   
73	 *      }
74	 *
75	 * RouteTree::find_by_rr_id() finds the RouteTreeNode for a given RRNodeId. Note that RRNodeId isn't a unique
76	 * key for SINK nodes and therefore an external lookup (generated from sink nodes returned by RouteTree::update_from_heap())
77	 * or a search may be required to find a certain SINK.
78	 *
79	 * When the occupancy and timing data is up to date, a tree can be sanity checked using RouteTree::is_valid().
80	 */
81	
82	#include <functional>
83	#include <iterator>
84	#include <mutex>
85	#include <unordered_map>
86	
87	#include "connection_based_routing_fwd.h"
88	#include "route_path_manager.h"
89	#include "route_tree_fwd.h"
90	#include "spatial_route_tree_lookup.h"
91	#include "vtr_dynamic_bitset.h"
92	#include "vtr_optional.h"
93	#include "vtr_range.h"
94	
95	/**
96	 * @brief A single route tree node
97	 *
98	 * Structure describing one node in a RouteTree. */
99	class RouteTreeNode {
100	    friend class RouteTree;
101	
102	  public:
103	    RouteTreeNode() = delete;
104	    RouteTreeNode(const RouteTreeNode&) = default;
105	    RouteTreeNode(RouteTreeNode&&) = default;
106	    RouteTreeNode& operator=(const RouteTreeNode&) = default;
107	    RouteTreeNode& operator=(RouteTreeNode&&) = default;
108	
109	    /** This struct makes little sense outside the context of a RouteTree.
110	     * This constructor is only public for compatibility purposes. */
111	    RouteTreeNode(RRNodeId inode, RRSwitchId parent_switch, RouteTreeNode* parent);
112	
113	    /** ID of the rr_node that corresponds to this node. */
114	    RRNodeId inode;
115	    /** Switch type driving this node (by its parent). */
116	    RRSwitchId parent_switch;
117	    /** Should this node be put on the heap as part of the partial
118	     * routing to act as a source for subsequent connections? */
119	    bool re_expand;
120	
121	  private:
122	    /** Is this a leaf? add_node and remove_child_if should be keeping this valid.
123	     * Needed to know if _next points to the first child */
124	    bool _is_leaf = true;
125	
126	  public:
127	    /** Time delay for the signal to get from the net source to this node.
128	     * Includes the time to go through this node. */
129	    float Tdel;
130	    /** Total upstream resistance from this node to the net
131	     * source, including any device_ctx.rr_nodes[].R of this node. */
132	    float R_upstream;
133	    /** Total downstream capacitance from this node. That is,
134	     * the total C of the subtree rooted at the current node,
135	     * including the C of the current node. */
136	    float C_downstream;
137	    /** Net pin index associated with the node. This value
138	     * ranges from 1 to fanout [1..num_pins-1]. For cases when
139	     * different speed paths are taken to the same SINK for
140	     * different pins, inode cannot uniquely identify each SINK,
141	     * so the net pin index guarantees an unique identification
142	     * for each SINK node. For non-SINK nodes and for SINK
143	     * nodes with no associated net pin index, (i.e. special 
144	     * SINKs like the source of a clock tree which do not
145	     * correspond to an actual netlist connection), the value
146	     * for this member should be set to OPEN (-1). */
147	    int net_pin_index;
148	
149	    /** Iterator implementation for child_nodes(). Walks using
150	     * _next_sibling ptrs. At the end of the child list, the ptr
151	     * points up to where the parent's subtree ends, so we know where
152	     * to stop */
153	    template<class ref>
154	    class RTIterator {
155	      public:
156	        using iterator_category = std::forward_iterator_tag;
157	        using difference_type = std::ptrdiff_t;
158	        using value_type = RouteTreeNode;
159	        using pointer = RouteTreeNode*;
160	        using reference = ref;
161	
162	        constexpr RTIterator(RouteTreeNode* p)
163	            : _p(p) {}
164	
165	        constexpr reference operator*() const {
166	            return const_cast<ref>(*_p);
167	        }
168	        inline RTIterator& operator++() {
169	            _p = _p->_next_sibling;
170	            return *this;
171	        }
172	        inline RTIterator operator++(int) {
173	            RTIterator tmp = *this;
174	            ++(*this);
175	            return tmp;
176	        }
177	        constexpr bool operator==(const RTIterator& rhs) { return _p == rhs._p; }
178	        constexpr bool operator!=(const RTIterator& rhs) { return _p != rhs._p; }
179	
180	      private:
181	        /** My current node */
182	        RouteTreeNode* _p;
183	    };
184	
185	    /** Recursive iterator implementation for a RouteTreeNode.
186	     * This walks over all child nodes of a given node without a stack
187	     * or recursion: we keep the nodes in depth-first order in the
188	     * linked list managed by RouteTree. Nodes know where their subtree
189	     * ends, so we can just walk the _next ptrs until we find that */
190	    template<class ref>
191	    class RTRecIterator {
192	      public:
193	        using iterator_category = std::forward_iterator_tag;
194	        using difference_type = std::ptrdiff_t;
195	        using value_type = RouteTreeNode;
196	        using pointer = RouteTreeNode*;
197	        using reference = ref;
198	
199	        constexpr RTRecIterator(RouteTreeNode* p)
200	            : _p(p) {}
201	
202	        constexpr reference operator*() const {
203	            return const_cast<ref>(*_p);
204	        }
205	        inline RTRecIterator& operator++() {
206	            _p = _p->_next;
207	            return *this;
208	        }
209	        inline RTRecIterator operator++(int) {
210	            RTRecIterator tmp = *this;
211	            ++(*this);
212	            return tmp;
213	        }
214	        constexpr bool operator==(const RTRecIterator& rhs) { return _p == rhs._p; }
215	        constexpr bool operator!=(const RTRecIterator& rhs) { return _p != rhs._p; }
216	
217	      private:
218	        /** My current node */
219	        RouteTreeNode* _p;
220	    };
221	
222	    /** Provide begin and end fns when iterating on this tree.
223	     * .child_nodes() returns Iterable<RTIterator> while .all_nodes() returns Iterable<RTRecIterator> */
224	    template<class Iterator>
225	    class Iterable {
226	      public:
227	        constexpr Iterable(RouteTreeNode* node1, RouteTreeNode* node2)
228	            : _node1(node1)
229	            , _node2(node2) {}
230	        constexpr Iterator begin() const { return Iterator(_node1); }
231	        constexpr Iterator end() const { return Iterator(_node2); }
232	
233	      private:
234	        RouteTreeNode* _node1;
235	        RouteTreeNode* _node2;
236	    };
237	
238	    /* Shorthands for different iterator types */
239	    using iterator = RTIterator<RouteTreeNode&>;
240	    using const_iterator = RTIterator<const RouteTreeNode&>;
241	    using rec_iterator = RTRecIterator<RouteTreeNode&>;
242	    using const_rec_iterator = RTRecIterator<const RouteTreeNode&>;
243	
244	    /* Shorthands for "iterable" types */
245	    template<class ref>
246	    using iterable = Iterable<RTIterator<ref>>;
247	    template<class ref>
248	    using rec_iterable = Iterable<RTRecIterator<ref>>;
249	
250	    /** Traverse child nodes. */
251	    constexpr iterable<const RouteTreeNode&> child_nodes(void) const {
252	        return iterable<const RouteTreeNode&>(_next, _subtree_end);
253	    }
254	
255	    /** Get parent node if exists. (nullopt if not) */
256	    constexpr vtr::optional<const RouteTreeNode&> parent(void) const {
257	        return _parent ? vtr::optional<const RouteTreeNode&>(*_parent) : vtr::nullopt;
258	    }
259	
260	    /** Traverse the subtree under this node in depth-first order. Doesn't include this node. */
261	    constexpr rec_iterable<const RouteTreeNode&> all_nodes(void) const {
262	        return rec_iterable<const RouteTreeNode&>(_next, _subtree_end);
263	    }
264	
265	    /** Print information about this subtree to stdout. */
266	    void print(void) const;
267	
268	    /** Is this node a leaf?
269	     *
270	     * True if the next node after this is not its child (we jumped up to the next branch)
271	     * or if it's null. The RouteTree functions keep the books for this. */
272	    constexpr bool is_leaf(void) const { return _is_leaf; }
273	
274	    /** Equality operator. For now, just compare the addresses */
275	    friend bool operator==(const RouteTreeNode& lhs, const RouteTreeNode& rhs) noexcept {
276	        return &lhs == &rhs;
277	    }
278	    friend bool operator!=(const RouteTreeNode& lhs, const RouteTreeNode& rhs) noexcept {
279	        return !(lhs == rhs);
280	    }
281	
282	  private:
283	    void print_x(int depth) const;
284	
285	    /** Traverse child nodes, mutable reference */
286	    constexpr iterable<RouteTreeNode&> _child_nodes(void) const {
287	        return iterable<RouteTreeNode&>(_next, _subtree_end);
288	    }
289	
290	    /** Traverse subtree, mutable reference */
291	    constexpr rec_iterable<RouteTreeNode&> _all_nodes(void) const {
292	        return rec_iterable<RouteTreeNode&>(_next, _subtree_end);
293	    }
294	
295	    /** Ptr to parent */
296	    RouteTreeNode* _parent = nullptr;
297	
298	    /** In the RouteTree, nodes are stored as a linked list in depth-first order.
299	     * This points to the next element in that list. If proper ordering is kept,
300	     * this also points to the first child of this node (given that it's not a leaf) */
301	    RouteTreeNode* _next = nullptr;
302	
303	    /** Having a doubly linked list helps maintain the ordering of nodes */
304	    RouteTreeNode* _prev = nullptr;
305	
306	    /** Here is the awkward part: these two pointers can become a union. 
307	     * 1. If there is a next sibling, _subtree_end is equal to it: when we finish walking the subtree we arrive at the next sibling.
308	     * 2. If there is not, _subtree_end is equal to the parent's _subtree_end.
309	     * So there is never a case where _next_sibling and _subtree_end are both valid and pointing at different things.
310	     * Then, the only question is where to stop when walking _next_sibling ptrs, since the final sibling won't point at nullptr.
311	     * But it will point at parent's _subtree_end, so we can use that as the limiting case */
312	    union {
313	        /* Ptr to "next sibling": used when traversing child nodes */
314	        RouteTreeNode* _next_sibling = nullptr;
315	        /* Where does the subtree under this node end in the flattened linked list? Needed when recursively iterating */
316	        RouteTreeNode* _subtree_end;
317	    };
318	};
