320	/** fwd definition for compatibility class in old_traceback.h */
321	class TracebackCompat;
322	
323	/**
324	 * @brief Each RTExploredNode element stores the node states for the connection router and represents a partial route.
325	 *
326	 * @note Only `index`, `prev_edge`, and `rcv_path_backward_delay` fields are used as the return value outside the connection router.
327	 */
328	class RTExploredNode {
329	  public:
330	    /* Used inside the connection router */
331	
332	    ///@brief The cost used to sort heap. For the timing-driven router this is the backward_path_cost
333	    /// plus the expected cost to the target.
334	    float total_cost = std::numeric_limits<float>::infinity();
335	    ///@brief The "known" cost of the path up to and including this node.
336	    float backward_path_cost = std::numeric_limits<float>::infinity();
337	    ///@brief Stores the upstream resistance to ground from this node in the path search (connection
338	    /// routing), including the resistance of the node itself (device_ctx.rr_nodes[index].R).
339	    float R_upstream = std::numeric_limits<float>::infinity();
340	    ///@brief Structure to handle extra RCV structures. Managed by PathManager class.
341	    t_heap_path* path_data = nullptr;
342	
343	    /* Used outside the connection router as the return values (`index` and `prev_edge` are also used inside the router). */
344	
345	    ///@brief The RR node index associated with the costs/R_upstream values. Outside the
346	    /// connection router, this field is mainly used in `RouteTree::update_from_heap` and
347	    /// `RouteTree::add_subtree_from_heap`. Inside the connection router, this is used as
348	    /// part of the node info passed as a parameter of some member functions.
349	    RRNodeId index = RRNodeId::INVALID();
350	    ///@brief The edge from the previous node used to reach the current. Same usage as the
351	    /// `index` field described above.
352	    RREdgeId prev_edge = RREdgeId::INVALID();
353	    ///@brief The delay of the partial path plus the path from route tree to source.
354	    /// Needed by RCV. Set to infinity if RCV is disabled. This field is used as part
355	    /// of the return value of the route routine, derived from the `path_data` pointer
356	    /// (but not using `path_data` for returning to avoid issues with dynamic memory
357	    /// management).
358	    float rcv_path_backward_delay = std::numeric_limits<float>::infinity();
359	};
360	
361	/**
362	 * @brief Top level route tree used in timing analysis and keeping routing state.
363	 *
364	 * Contains the root node and a lookup from RRNodeIds to RouteTreeNode&s in the tree. */
365	class RouteTree {
366	    friend class TracebackCompat;
367	
368	  public:
369	    RouteTree() = delete;
370	    RouteTree(const RouteTree&);
371	    RouteTree(RouteTree&&);
372	    RouteTree& operator=(const RouteTree&);
373	    RouteTree& operator=(RouteTree&&);
374	
375	    /** Return a RouteTree initialized to inode.
376	     * Note that prune() won't work on a RouteTree initialized this way (see _net_id comments) */
377	    RouteTree(RRNodeId inode);
378	    /** Return a RouteTree initialized to the source of nets[inet].
379	     * Use this constructor where possible (needed for prune() to work) */
380	    RouteTree(ParentNetId inet);
381	
382	    ~RouteTree() {
383	        std::unique_lock<std::mutex> write_lock(_write_mutex);
384	        free_list(_root);
385	    }
386	
387	    /** Add the most recently finished wire segment to the routing tree, and
388	     * update the Tdel, etc. numbers for the rest of the routing tree. hptr
389	     * is the heap pointer of the SINK that was reached, and target_net_pin_index
390	     * is the net pin index corresponding to the SINK that was reached. This routine
391	     * returns a tuple: RouteTreeNode of the branch it adds to the route tree and
392	     * RouteTreeNode of the SINK it adds to the routing.
393	     * Locking operation: only one thread can update_from_heap() a RouteTree at a time. */
394	    std::tuple<vtr::optional<const RouteTreeNode&>, vtr::optional<const RouteTreeNode&>>
395	    update_from_heap(RTExploredNode* hptr, int target_net_pin_index, SpatialRouteTreeLookup* spatial_rt_lookup, bool is_flat);
396	
397	    /** Reload timing values (R_upstream, C_downstream, Tdel).
398	     * Can take a RouteTreeNode& to do an incremental update.
399	     * Note that update_from_heap already does this, but prune() doesn't.
400	     * Locking operation: only one thread can reload_timing() for a RouteTree at a time. */
401	    void reload_timing(vtr::optional<RouteTreeNode&> from_node = vtr::nullopt);
402	
403	    /** Get the RouteTreeNode corresponding to the RRNodeId. Returns nullopt if not found.
404	     * SINK nodes may be added to the tree multiple times. In that case, this will return the last one added.
405	     * Use find_by_isink for a more accurate lookup. */
406	    vtr::optional<const RouteTreeNode&> find_by_rr_id(RRNodeId rr_node) const;
407	
408	    /** Get the sink RouteTreeNode associated with the isink. 
409	     * Will probably segfault if the tree is not constructed with a ParentNetId. */
410	    inline vtr::optional<const RouteTreeNode&> find_by_isink(int isink) const {
411	        RouteTreeNode* x = _isink_to_rt_node[isink - 1];
412	        return x ? vtr::optional<const RouteTreeNode&>(*x) : vtr::nullopt;
413	    }
414	
415	    /** Get the number of sinks in associated net. */
416	    constexpr size_t num_sinks(void) const {
417	        return _num_sinks;
418	    }
419	
420	    /** Check the consistency of this route tree. Looks for:
421	     * - invalid parent-child links
422	     * - invalid timing values
423	     * - congested SINKs
424	     * Returns true if OK. */
425	    bool is_valid(void) const;
426	
427	    /** Check if the tree has any overused nodes (-> the tree is congested).
428	     * Returns true if not congested. */
429	    bool is_uncongested(void) const;
430	
431	    /** Print information about this route tree to stdout. */
432	    void print(void) const;
433	
434	    /** Prune overused nodes from the tree.
435	     * Also prune unused non-configurable nodes if non_config_node_set_usage is provided (see get_non_config_node_set_usage)
436	     * Returns nullopt if the entire tree is pruned.
437	     * Locking operation: only one thread can prune() a RouteTree at a time. */
438	    vtr::optional<RouteTree&> prune(CBRR& connections_inf, std::vector<int>* non_config_node_set_usage = nullptr);
439	
440	    /** Remove all sinks and mark the remaining nodes as un-expandable.
441	     * This is used after routing a clock net.
442	     * TODO: is this function doing anything? Try running without it
443	     * Locking operation: only one thread can freeze() a RouteTree at a time. */
444	    void freeze(void);
445	
446	    /** Count configurable edges to non-configurable node sets. (rr_nonconf_node_sets index -> int)
447	     * Required when using prune() to remove non-configurable nodes. */
448	    std::vector<int> get_non_config_node_set_usage(void) const;
449	
450	    /* Wrapper for the recursive iterator. */
451	    using iterator = RouteTreeNode::RTRecIterator<const RouteTreeNode&>;
452	    using iterable = RouteTreeNode::Iterable<RouteTreeNode::const_rec_iterator>;
453	
454	    /** Get an iterable for all nodes in this RouteTree. */
455	    constexpr iterable all_nodes(void) const { return iterable(_root, nullptr); }
456	
457	    /** Get a reference to the root RouteTreeNode. */
458	    constexpr const RouteTreeNode& root(void) const { return *_root; } /* this file is 90% const and 10% code */
459	
460	    /** Iterator implementation for remaining or reached isinks. Goes over [1..num_sinks]
461	     * and only returns a value when the sink state is right */
462	    template<bool sink_state>
463	    class IsinkIterator {
464	      public:
465	        using iterator_category = std::forward_iterator_tag;
466	        using difference_type = std::ptrdiff_t;
467	        using value_type = int;
468	        using pointer = int*;
469	        using reference = int&;
470	
471	        constexpr IsinkIterator(const vtr::dynamic_bitset<>& bitset, size_t x)
472	            : _bitset(bitset)
473	            , _x(x) {
474	            if (_x < _bitset.size() && _bitset.get(_x) != sink_state) /* Iterate forward to a valid state */
475	                ++(*this);
476	        }
477	        constexpr value_type operator*() const {
478	            return _x;
479	        }
480	        inline IsinkIterator& operator++() {
481	            _x++;
482	            for (; _x < _bitset.size() && _bitset.get(_x) != sink_state; _x++)
483	                ;
484	            return *this;
485	        }
486	        inline IsinkIterator operator++(int) {
487	            IsinkIterator tmp = *this;
488	            ++(*this);
489	            return tmp;
490	        }
491	        constexpr bool operator==(const IsinkIterator& rhs) { return _x == rhs._x; }
492	        constexpr bool operator!=(const IsinkIterator& rhs) { return _x != rhs._x; }
493	
494	      private:
495	        /** Ref to the bitset */
496	        const vtr::dynamic_bitset<>& _bitset;
497	        /** Current position */
498	        size_t _x;
499	    };
500	
501	    typedef vtr::Range<IsinkIterator<true>> reached_isink_range;
502	    typedef vtr::Range<IsinkIterator<false>> remaining_isink_range;
503	
504	    /** Get a lookup which contains the "isink reached state".
505	     * It's a 1-indexed! bitset of "pin indices". True if the nth sink has been reached, false otherwise.
506	     * If you call it before prune() and after routing, there's no guarantee on whether the reached sinks
507	     * are reached legally.
508	     * Another catch is that vtr::dynamic_bitsets don't know their size, so keep tree.num_sinks()+1
509	     * as a limit when iterating over this. */
510	    constexpr const vtr::dynamic_bitset<>& get_is_isink_reached(void) const { return _is_isink_reached; }
511	
512	    /** Get reached isinks: 1-indexed pin indices enumerating the sinks in this net.
513	     * "Reached" means "reached legally" if you call this after prune() and not before any routing.
514	     * Otherwise it doesn't guarantee legality.
515	     * Builds and returns a value: use get_is_isink_reached directly if you want speed. */
516	    constexpr reached_isink_range get_reached_isinks(void) const {
517	        return vtr::make_range(IsinkIterator<true>(_is_isink_reached, 1), IsinkIterator<true>(_is_isink_reached, _num_sinks + 1));
518	    }
519	
520	    /** Get remaining (not routed (legally?)) isinks:
521	     * 1-indexed pin indices enumerating the sinks in this net.
522	     * Caveats in get_reached_isinks() apply. */
523	    constexpr remaining_isink_range get_remaining_isinks(void) const {
524	        return vtr::make_range(IsinkIterator<false>(_is_isink_reached, 1), IsinkIterator<false>(_is_isink_reached, _num_sinks + 1));
525	    }
526	
527	  private:
528	    std::tuple<vtr::optional<RouteTreeNode&>, vtr::optional<RouteTreeNode&>>
529	    add_subtree_from_heap(RTExploredNode* hptr, int target_net_pin_index, bool is_flat);
530	
531	    void add_non_configurable_nodes(RouteTreeNode* rt_node,
532	                                    bool reached_by_non_configurable_edge,
533	                                    std::unordered_set<RRNodeId>& visited,
534	                                    bool is_flat);
535	
536	    void reload_timing_unlocked(vtr::optional<RouteTreeNode&> from_node = vtr::nullopt);
537	    void load_new_subtree_R_upstream(RouteTreeNode& from_node);
538	    float load_new_subtree_C_downstream(RouteTreeNode& from_node);
539	    RouteTreeNode& update_unbuffered_ancestors_C_downstream(RouteTreeNode& from_node);
540	    void load_route_tree_Tdel(RouteTreeNode& from_node, float Tarrival);
541	
542	    bool is_valid_x(const RouteTreeNode& rt_node) const;
543	    bool is_uncongested_x(const RouteTreeNode& rt_node) const;
544	
545	    vtr::optional<RouteTreeNode&>
546	    prune_x(RouteTreeNode& rt_node,
547	            CBRR& connections_inf,
548	            bool force_prune,
549	            std::vector<int>* non_config_node_set_usage);
550	
551	    void freeze_x(RouteTreeNode& rt_node);
552	
553	    /** Add node to parent, set up prev/next links, set up parent-child links and update lookup. */
554	    inline void add_node(RouteTreeNode* parent, RouteTreeNode* node) {
555	        node->_prev = parent;
556	        node->_next = parent->_next;
557	        if (parent->_next)
558	            parent->_next->_prev = node;
559	
560	        node->_parent = parent;
561	        /* If parent is a leaf, its _next ptr isn't a child node. Update _subtree_end
562	         * Otherwise, update the sibling ptr, since a sibling exists, it's the end of our subtree.
563	         * These two pointers are a union, see RouteTreeNode definition for details */
564	        if (parent->is_leaf()) {
565	            node->_subtree_end = parent->_subtree_end;
566	        } else {
567	            node->_next_sibling = parent->_next;
568	        }
569	        parent->_next = node;
570	
571	        /** Add node to RR to RT lookup */
572	        _rr_node_to_rt_node[node->inode] = node;
573	        /** If node is a SINK (net_pin_index > 0), also add it to sink RT lookup */
574	        if (node->net_pin_index > 0 && _net_id.is_valid())
575	            _isink_to_rt_node[node->net_pin_index - 1] = node;
576	
577	        /* Now it's a branch */
578	        parent->_is_leaf = false;
579	    }
580	
581	    /** Free all nodes after node */
582	    inline void free_list(RouteTreeNode* node) {
583	        RouteTreeNode* p = node;
584	        while (p) {
585	            RouteTreeNode* x = p;
586	            p = p->_next;
587	            free_node(x);
588	        }
589	    }
590	
591	    /** Make a copy of rhs and return it. Updates _rr_node_to_rt_node */
592	    RouteTreeNode* copy_tree(const RouteTreeNode* rhs);
593	
594	    /** Helper for copy_list: copy child nodes of rhs into lhs */
595	    void copy_tree_x(RouteTreeNode* lhs, const RouteTreeNode& rhs);
596	
597	    /** Free a node. Only keeps the linked list valid (not the tree ptrs) */
598	    inline void free_node(RouteTreeNode* node) {
599	        if (node->_prev)
600	            node->_prev->_next = node->_next;
601	        if (node->_next)
602	            node->_next->_prev = node->_prev;
603	        delete node;
604	    }
605	
606	    /** Iterate through parent's child nodes and remove if p returns true.
607	     * Updates tree ptrs and _rr_node_to_rt_node. */
608	    inline void remove_child_if(RouteTreeNode& parent, const std::function<bool(RouteTreeNode&)>& p) {
609	        RouteTreeNode* curr = parent._next;
610	        RouteTreeNode* prev = nullptr;
611	        RouteTreeNode* end = parent._subtree_end;
612	        while (curr != end) {
613	            if (p(*curr)) {
614	                _rr_node_to_rt_node.erase(curr->inode);
615	                /* Here is a tricky part: when updating prev's _next_sibling, we need to also
616	                 * update the _subtree_end/_next_sibling ptrs of prev's subtree. We know that
617	                 * _next_sibling points to _subtree_end in the last ("rightmost") node of every
618	                 * level. _subtree_end's _prev will take us to the rightmost leaf in the subtree,
619	                 * and from there we can walk up via _parent ptrs and update along the way */
620	                if (prev) {
621	                    RouteTreeNode* q = prev->_subtree_end->_prev;
622	                    while (q != prev) {
623	                        q->_subtree_end = curr->_subtree_end;
624	                        q = q->_parent;
625	                    }
626	                    prev->_next_sibling = curr->_next_sibling;
627	                }
628	                RouteTreeNode* x = curr;
629	                curr = curr->_next_sibling;
630	                free_node(x);
631	            } else {
632	                prev = curr;
633	                curr = curr->_next_sibling;
634	            }
635	        }
636	        /* did this node become a leaf? */
637	        if (parent._next == nullptr || parent._next->_parent != &parent)
638	            parent._is_leaf = true;
639	    }
640	
641	    /** Root node.
642	     * This is also the internal node list via the ptrs in RouteTreeNode. */
643	    RouteTreeNode* _root;
644	
645	    /** Net ID.
646	     * A RouteTree does not have to be connected to a net, but if it isn't
647	     * constructed using a ParentNetId prune() won't work. This is due to
648	     * a data dependency through "Connection_based_routing_resources". Should
649	     * be refactored when possible. */
650	    ParentNetId _net_id;
651	
652	    /** Lookup from RRNodeIds to RouteTreeNodes in the tree.
653	     * In some cases the same SINK node is put into the tree multiple times in a
654	     * single route. To model this, we are putting in separate rt_nodes in the route
655	     * tree if we go to the same SINK more than once. rr_node_to_rt_node[inode] will
656	     * therefore store the last rt_node created of all the SINK nodes with the same
657	     * index "inode". */
658	    std::unordered_map<RRNodeId, RouteTreeNode*> _rr_node_to_rt_node;
659	
660	    /** RRNodeId is not a unique lookup for sink RouteTreeNodes, but net_pin_index
661	     * is. Store a 0-indexed lookup here for users who need to look up a sink from
662	     * a net_pin_index, ipin, isink, etc. */
663	    std::vector<RouteTreeNode*> _isink_to_rt_node;
664	
665	    /** Is Nth sink in this net reached?
666	     * Bitset of [1..num_sinks]. (1-indexed!)
667	     * We work with these indices, because they are used in a bunch of lookups in
668	     * the router. Looking these back up from sink RR nodes would require looking
669	     * up its RouteTreeNode and then the net_pin_index from that. */
670	    vtr::dynamic_bitset<> _is_isink_reached;
671	
672	    /** Number of sinks in this tree's net. Useful for iteration. */
673	    size_t _num_sinks;
674	
675	    /** Write mutex on this RouteTree. Acquired by the write operations automatically:
676	     * the caller does not need to know about a lock. */
677	    std::mutex _write_mutex;
678	};
