6	#include "read_route.h"
7	#include "route.h"
8	#include "route_common.h"
9	#include "route_debug.h"
10	#include "route_profiling.h"
11	#include "route_utils.h"
12	#include "rr_graph.h"
13	#include "router_lookahead_report.h"
14	#include "vtr_time.h"
15	#include "vtr_expr_eval.h"
16	
17	bool route(const Netlist<>& net_list,
18	           int width_fac,
19	           const t_router_opts& router_opts,
20	           const t_crr_opts& crr_opts,
21	           const t_analysis_opts& analysis_opts,
22	           t_det_routing_arch& det_routing_arch,
23	           std::vector<t_segment_inf>& segment_inf,
24	           NetPinsMatrix<float>& net_delay,
25	           std::shared_ptr<SetupHoldTimingInfo> timing_info,
26	           std::shared_ptr<RoutingDelayCalculator> delay_calc,
27	           t_chan_width_dist chan_width_dist,
28	           const std::vector<t_direct_inf>& directs,
29	           ScreenUpdatePriority first_iteration_priority,
30	           bool is_flat) {
31	    auto& device_ctx = g_vpr_ctx.mutable_device();
32	    const auto& cluster_ctx = g_vpr_ctx.clustering();
33	    const auto& atom_ctx = g_vpr_ctx.atom();
34	    auto& route_ctx = g_vpr_ctx.mutable_routing();
35	
36	    if (net_list.nets().empty()) {
37	        VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "No nets to route\n");
38	    }
39	
40	    e_graph_type graph_type;
41	    e_graph_type graph_directionality;
42	    if (router_opts.route_type == e_route_type::GLOBAL) {
43	        graph_type = e_graph_type::GLOBAL;
44	        graph_directionality = e_graph_type::BIDIR;
45	    } else {
46	        graph_type = (det_routing_arch.directionality == BI_DIRECTIONAL ? e_graph_type::BIDIR : e_graph_type::UNIDIR);
47	        if (det_routing_arch.directionality == UNI_DIRECTIONAL && det_routing_arch.tileable) {
48	            graph_type = e_graph_type::UNIDIR_TILEABLE;
49	        }
50	        graph_directionality = (det_routing_arch.directionality == BI_DIRECTIONAL ? e_graph_type::BIDIR : e_graph_type::UNIDIR);
51	    }
52	
53	    /* Set the channel widths */
54	    t_chan_width chan_width = init_chan(width_fac, chan_width_dist, graph_directionality);
55	
56	    /* Set up the routing resource graph defined by this FPGA architecture. */
57	    int warning_count;
58	
59	    create_rr_graph(graph_type,
60	                    device_ctx.physical_tile_types,
61	                    device_ctx.grid,
62	                    chan_width,
63	                    det_routing_arch,
64	                    segment_inf,
65	                    router_opts,
66	                    crr_opts,
67	                    directs,
68	                    &warning_count,
69	                    is_flat);
70	
71	    //Initialize drawing, now that we have an RR graph
72	    init_draw_coords(width_fac, g_vpr_ctx.placement().blk_loc_registry());
73	
74	    /* Allocate and load additional rr_graph information needed only by the router. */
75	    alloc_and_load_rr_node_route_structs(router_opts);
76	
77	    init_route_structs(net_list,
78	                       router_opts.bb_factor,
79	                       router_opts.has_choke_point,
80	                       is_flat);
81	
82	    IntraLbPbPinLookup intra_lb_pb_pin_lookup(device_ctx.logical_block_types);
83	    ClusteredPinAtomPinsLookup netlist_pin_lookup(cluster_ctx.clb_nlist, atom_ctx.netlist(), intra_lb_pb_pin_lookup);
84	
85	    auto choking_spots = set_nets_choking_spots(net_list,
86	                                                route_ctx.net_terminal_groups,
87	                                                route_ctx.net_terminal_group_num,
88	                                                router_opts.has_choke_point,
89	                                                is_flat);
90	
91	    //Initially, the router runs normally trying to reduce congestion while
92	    //balancing other metrics (timing, wirelength, run-time etc.)
93	    RouterCongestionMode router_congestion_mode = RouterCongestionMode::NORMAL;
94	
95	    //Initialize and properly size the lookups for profiling
96	    profiling::profiling_initialization(get_max_pins_per_net(net_list));
97	
98	    /*
99	     * Configure the routing predictor
100	     */
101	    RoutingPredictor routing_predictor;
102	    float abort_iteration_threshold = std::numeric_limits<float>::infinity(); //Default no early abort
103	    if (router_opts.routing_failure_predictor == SAFE) {
104	        abort_iteration_threshold = ROUTING_PREDICTOR_ITERATION_ABORT_FACTOR_SAFE * router_opts.max_router_iterations;
105	    } else if (router_opts.routing_failure_predictor == AGGRESSIVE) {
106	        abort_iteration_threshold = ROUTING_PREDICTOR_ITERATION_ABORT_FACTOR_AGGRESSIVE * router_opts.max_router_iterations;
107	    } else {
108	        VTR_ASSERT_MSG(router_opts.routing_failure_predictor == OFF, "Unrecognized routing failure predictor setting");
109	    }
110	
111	    float high_effort_congestion_mode_iteration_threshold = router_opts.congested_routing_iteration_threshold_frac * router_opts.max_router_iterations;
112	
113	    /* Set delay of ignored signals to zero. Non-ignored net delays are set by
114	     * update_net_delays_from_route_tree() inside timing_driven_route_net(),
115	     * which is only called for non-ignored nets. */
116	    for (auto net_id : net_list.nets()) {
117	        if (net_list.net_is_ignored(net_id)) {
118	            for (unsigned int ipin = 1; ipin < net_list.net_pins(net_id).size(); ++ipin) {
119	                net_delay[net_id][ipin] = 0.;
120	            }
121	        }
122	    }
123	
124	    CBRR connections_inf{net_list, route_ctx.net_rr_terminals, is_flat};
125	
126	    route_budgets budgeting_inf(net_list, is_flat);
127	
128	    // This needs to be called before filling intra-cluster lookahead maps to ensure that the intra-cluster lookahead maps are initialized.
129	    const RouterLookahead* router_lookahead = get_cached_router_lookahead(det_routing_arch,
130	                                                                          router_opts.lookahead_type,
131	                                                                          router_opts.write_router_lookahead,
132	                                                                          router_opts.read_router_lookahead,
133	                                                                          segment_inf,
134	                                                                          is_flat,
135	                                                                          router_opts.route_verbosity,
136	                                                                          router_opts.device_model_warnings,
137	                                                                          router_opts.router_lookahead_interposer_base_cut_multiplier);
138	
139	    if (is_flat) {
140	        // If is_flat is true, the router lookahead maps related to intra-cluster resources should be initialized since
141	        // they haven't been initialized when the map related to global resources was initialized.
142	        auto cache_key = route_ctx.router_lookahead_cache_key_;
143	        std::unique_ptr<RouterLookahead> mut_router_lookahead(route_ctx.cached_router_lookahead_.release());
144	        VTR_ASSERT(mut_router_lookahead);
145	        route_ctx.cached_router_lookahead_.clear();
146	        if (!router_opts.read_intra_cluster_router_lookahead.empty()) {
147	            mut_router_lookahead->read_intra_cluster(router_opts.read_intra_cluster_router_lookahead);
148	        } else {
149	            mut_router_lookahead->compute_intra_tile();
150	        }
151	        route_ctx.cached_router_lookahead_.set(cache_key, std::move(mut_router_lookahead));
152	        router_lookahead = get_cached_router_lookahead(det_routing_arch,
153	                                                       router_opts.lookahead_type,
154	                                                       router_opts.write_router_lookahead,
155	                                                       router_opts.read_router_lookahead,
156	                                                       segment_inf,
157	                                                       is_flat,
158	                                                       router_opts.route_verbosity,
159	                                                       router_opts.device_model_warnings,
160	                                                       router_opts.router_lookahead_interposer_base_cut_multiplier);
161	        if (!router_opts.write_intra_cluster_router_lookahead.empty()) {
162	            router_lookahead->write_intra_cluster(router_opts.write_intra_cluster_router_lookahead);
163	        }
164	    }
165	
166	    VTR_ASSERT(router_lookahead != nullptr);
167	
168	    // After the router lookahead has been fully created, generate the router
169	    // lookahead report if requested.
170	    if (router_opts.generate_router_lookahead_report) {
171	        generate_router_lookahead_report(router_lookahead, router_opts);
172	    }
173	
174	    /* Routing parameters */
175	    float pres_fac = router_opts.first_iter_pres_fac;
176	    update_draw_pres_fac(pres_fac); /* Typically 0 -> ignore cong. */
177	    int bb_fac = router_opts.bb_factor;
178	
179	    /* When routing conflicts are detected the bounding boxes are scaled
180	     * by BB_SCALE_FACTOR every BB_SCALE_ITER_COUNT iterations */
181	    constexpr float BB_SCALE_FACTOR = 2;
182	    constexpr int BB_SCALE_ITER_COUNT = 5;
183	
184	    size_t available_wirelength = calculate_wirelength_available();
185	
186	    /* Routing status and metrics */
187	    bool success = false;
188	    WirelengthInfo wirelength_info;
189	    OveruseInfo overuse_info(device_ctx.rr_graph.num_nodes());
190	    tatum::TimingPathInfo critical_path;
191	    int itry; //Routing iteration number
192	    int itry_conflicted_mode = 0;
193	
194	    /* Best result so far */
195	    vtr::vector<ParentNetId, vtr::optional<RouteTree>> best_routing;
196	    t_clb_opins_used best_clb_opins_used_locally;
197	    RoutingMetrics best_routing_metrics;
198	    int legal_convergence_count = 0;
199	
200	    /* Get initial criticalities from the lookahead */
201	    if (router_opts.with_timing_analysis && router_opts.initial_timing == e_router_initial_timing::LOOKAHEAD) {
202	        vtr::ScopedStartFinishTimer init_timing_timer("Initializing router criticalities");
203	        //Estimate initial connection delays from the router lookahead
204	        init_net_delay_from_lookahead(*router_lookahead,
205	                                      net_list,
206	                                      route_ctx.net_rr_terminals,
207	                                      net_delay,
208	                                      device_ctx.rr_graph,
209	                                      is_flat);
210	
211	        //Run STA to get estimated criticalities
212	        timing_info->update();
213	        VTR_LOG("Initial Net Connection Criticality Histogram:\n");
214	        print_router_criticality_histogram(net_list, *timing_info, netlist_pin_lookup, is_flat);
215	    }
216	
217	    std::unique_ptr<NetPinTimingInvalidator> pin_timing_invalidator;
218	    pin_timing_invalidator = make_net_pin_timing_invalidator(
219	        router_opts.timing_update_type,
220	        net_list,
221	        netlist_pin_lookup,
222	        atom_ctx.netlist(),
223	        atom_ctx.lookup(),
224	        timing_info,
225	        is_flat);
226	
227	    std::unique_ptr<NetlistRouter> netlist_router = make_netlist_router(
228	        net_list,
229	        router_lookahead,
230	        router_opts,
231	        connections_inf,
232	        net_delay,
233	        netlist_pin_lookup,
234	        timing_info,
235	        pin_timing_invalidator.get(),
236	        budgeting_inf,
237	        routing_predictor,
238	        choking_spots,
239	        is_flat,
240	        router_opts.route_verbosity);
241	
242	    RouterStats router_stats;
243	    float prev_iter_cumm_time = 0;
244	    vtr::Timer iteration_timer;
245	    int num_net_bounding_boxes_updated = 0;
246	    int itry_since_last_convergence = -1;
247	
248	    // This heap is used for reserve_locally_used_opins.
249	    FourAryHeap small_heap;
250	    small_heap.init_heap(device_ctx.grid);
251	
252	    // When RCV is enabled the router will not stop unless negative hold slack is 0
253	    // In some cases this isn't doable, due to global nets or intracluster routing issues
254	    // In these cases RCV will finish early if it goes RCV_FINISH_EARLY_COUNTDOWN iterations without detecting resolvable negative hold slack
255	    // Increasing this will make the router fail occasionally, decreasing will sometimes not let all hold violations be resolved
256	    constexpr int RCV_FINISH_EARLY_COUNTDOWN = 15;
257	
258	    int rcv_finished_count = RCV_FINISH_EARLY_COUNTDOWN;
259	
260	    print_route_status_header();
261	#ifndef NO_GRAPHICS
262	    // Reset router iteration in the current route attempt.
263	    get_bp_state_globals()->get_glob_breakpoint_state()->router_iter = 0;
264	#endif
265	    for (itry = 1; itry <= router_opts.max_router_iterations; ++itry) {
266	        /* Reset "is_routed" and "is_fixed" flags to indicate nets not pre-routed (yet) */
267	        for (auto net_id : net_list.nets()) {
268	            route_ctx.net_status.set_is_routed(net_id, false);
269	            route_ctx.net_status.set_is_fixed(net_id, false);
270	        }
271	
272	        if (itry_since_last_convergence >= 0) {
273	            ++itry_since_last_convergence;
274	        }
275	
276	        // Calculate this once and pass it into net routing to check if should reroute for hold
277	        float worst_negative_slack = 0;
278	        if (budgeting_inf.if_set()) {
279	            worst_negative_slack = timing_info->hold_total_negative_slack();
280	        }
281	
282	#ifndef NO_GRAPHICS
283	        // Update router information and check breakpoint.
284	        update_router_info_and_check_bp(BP_ROUTE_ITER, -1);
285	#endif
286	
287	        /* Initial criticalities: set to 1 on the first iter if the user asked for it */
288	        if (router_opts.initial_timing == e_router_initial_timing::ALL_CRITICAL && itry == 1)
289	            netlist_router->set_timing_info(make_constant_timing_info(1));
290	        else
291	            netlist_router->set_timing_info(timing_info);
292	
293	        /* Route each net */
294	        RouteIterResults iter_results = netlist_router->route_netlist(itry, pres_fac, worst_negative_slack);
295	
296	        if (!iter_results.is_routable) { /* Disconnected RRG */
297	            return false;
298	        }
299	
300	        // Make sure any CLB OPINs used up by subblocks being hooked directly to them are reserved for that purpose
301	        bool rip_up_local_opins = (itry == 1 ? false : true);
302	        if (!is_flat) {
303	            reserve_locally_used_opins(&small_heap, pres_fac,
304	                                       router_opts.acc_fac, rip_up_local_opins, is_flat);
305	        }
306	
307	        /*
308	         * Calculate metrics for the current routing
309	         */
310	        bool routing_is_feasible = feasible_routing();
311	        float est_success_iteration = routing_predictor.estimate_success_iteration();
312	
313	        //Update resource costs and overuse info
314	        if (itry == 1) {
315	            pathfinder_update_acc_cost_and_overuse_info(0., overuse_info); /* Acc_fac=0 for first iter. */
316	        } else {
317	            pathfinder_update_acc_cost_and_overuse_info(router_opts.acc_fac, overuse_info);
318	        }
319	
320	        wirelength_info = calculate_wirelength_info(net_list, available_wirelength);
321	        routing_predictor.add_iteration_overuse(itry, overuse_info.overused_nodes);
322	
323	        //Update timing based on the new routing
324	        //Note that the net delays have already been updated by timing_driven_route_net
325	        timing_info->update();
326	        timing_info->set_warn_unconstrained(false); //Don't warn again about unconstrained nodes again during routing
327	        pin_timing_invalidator->reset();
328	
329	        critical_path = timing_info->least_slack_critical_path();
330	
331	        VTR_ASSERT_SAFE(!router_opts.with_timing_analysis || check_net_delays(net_list, net_delay));
332	
333	        if (itry == 1 && router_opts.with_timing_analysis) {
334	            generate_route_timing_reports(router_opts, analysis_opts, *timing_info, *delay_calc, is_flat);
335	        }
336	
337	        float iter_cumm_time = iteration_timer.elapsed_sec();
338	        float iter_elapsed_time = iter_cumm_time - prev_iter_cumm_time;
339	
340	        std::string iteration_msg = "Iteration " + std::to_string(itry) + " took " + std::to_string(iter_elapsed_time) + " s";
341	
342	        PartitionTreeDebug::log(iteration_msg);
343	
344	        //Output progress
345	        print_route_status(itry, iter_elapsed_time, pres_fac, num_net_bounding_boxes_updated, iter_results.stats, overuse_info, wirelength_info, timing_info, est_success_iteration);
346	
347	        prev_iter_cumm_time = iter_cumm_time;
348	
349	        //Update graphics
350	        if (itry == 1) {
351	            update_screen(first_iteration_priority, ("Initial Route: " + iteration_msg).c_str(), e_pic_type::ROUTING, timing_info);
352	        } else {
353	            update_screen(ScreenUpdatePriority::MINOR, ("Route: " + iteration_msg).c_str(), e_pic_type::ROUTING, timing_info);
354	        }
355	
356	        if (router_opts.save_routing_per_iteration) {
357	            std::string filename = vtr::string_fmt("iteration_%03d.route", itry);
358	            print_route(net_list, nullptr, filename.c_str(), is_flat);
359	        }
360	
361	        //Update router stats (total)
362	        router_stats.combine(iter_results.stats);
363	
364	        /*
365	         * Are we finished?
366	         */
367	        if (is_iteration_complete(routing_is_feasible, router_opts, itry, timing_info, rcv_finished_count == 0)) {
368	            auto& router_ctx = g_vpr_ctx.routing();
369	
370	            if (is_better_quality_routing(best_routing, best_routing_metrics, wirelength_info, timing_info)) {
371	                //Save routing
372	                best_routing = router_ctx.route_trees;
373	                best_clb_opins_used_locally = router_ctx.clb_opins_used_locally;
374	
375	                success = true;
376	
377	                //Update best metrics
378	                if (router_opts.with_timing_analysis) {
379	                    check_net_delays(net_list, net_delay);
380	                    best_routing_metrics.sTNS = timing_info->setup_total_negative_slack();
381	                    best_routing_metrics.sWNS = timing_info->setup_worst_negative_slack();
382	                    best_routing_metrics.hTNS = timing_info->hold_total_negative_slack();
383	                    best_routing_metrics.hWNS = timing_info->hold_worst_negative_slack();
384	                    best_routing_metrics.critical_path = critical_path;
385	                }
386	                best_routing_metrics.used_wirelength = wirelength_info.used_wirelength();
387	            }
388	
389	            //Decrease pres_fac so that critical connections will take more direct routes
390	            //Note that we use first_iter_pres_fac here (typically zero), and switch to
391	            //use initial_pres_fac on the next iteration.
392	            pres_fac = router_opts.first_iter_pres_fac;
393	            update_draw_pres_fac(pres_fac);
394	
395	            //Reduce timing tolerances to re-route more delay-suboptimal signals
396	            connections_inf.set_connection_criticality_tolerance(0.7);
397	            connections_inf.set_connection_delay_tolerance(1.01);
398	
399	            ++legal_convergence_count;
400	            itry_since_last_convergence = 0;
401	
402	            VTR_ASSERT(success);
403	        }
404	
405	        if (itry_since_last_convergence == 1) {
406	            //We used first_iter_pres_fac when we started routing again
407	            //after the first routing convergence. Since that is often zero,
408	            //we want to set pres_fac to a reasonable (i.e. typically non-zero)
409	            //value afterwards -- so it grows when multiplied by pres_fac_mult
410	            pres_fac = router_opts.initial_pres_fac;
411	            update_draw_pres_fac(pres_fac);
412	        }
413	
414	        //Have we converged the maximum number of times, did not make any changes, or does it seem
415	        //unlikely additional convergences will improve QoR?
416	        if (legal_convergence_count >= router_opts.max_convergence_count
417	            || iter_results.stats.connections_routed == 0
418	            || early_reconvergence_exit_heuristic(router_opts, itry_since_last_convergence, timing_info, best_routing_metrics)) {
419	            break; //Done routing
420	        }
421	
422	        /*
423	         * Abort checks: Should we give-up because this routing problem is unlikely to converge to a legal routing?
424	         */
425	        if (itry == 1 && early_exit_heuristic(router_opts, wirelength_info)) {
426	            //Abort
427	            break;
428	        }
429	
430	        //Estimate at what iteration we will converge to a legal routing
431	        if (overuse_info.overused_nodes > ROUTING_PREDICTOR_MIN_ABSOLUTE_OVERUSE_THRESHOLD) {
432	            //Only consider aborting if we have a significant number of overused resources
433	
434	            if (!std::isnan(est_success_iteration) && est_success_iteration > abort_iteration_threshold && router_opts.routing_budgets_algorithm != YOYO) {
435	                VTR_LOG("Routing aborted, the predicted iteration for a successful route (%.1f) is too high.\n", est_success_iteration);
436	                break; //Abort
437	            }
438	        }
439	
440	        if (itry == 1 && router_opts.exit_after_first_routing_iteration) {
441	            VTR_LOG("Exiting after first routing iteration as requested\n");
442	            break;
443	        }
444	
445	        /*
446	         * Prepare for the next iteration
447	         */
448	        if (router_opts.route_bb_update == e_route_bb_update::DYNAMIC) {
449	            dynamic_update_bounding_boxes(iter_results.rerouted_nets, iter_results.bb_updated_nets);
450	        }
451	
452	        num_net_bounding_boxes_updated = iter_results.bb_updated_nets.size();
453	        netlist_router->handle_bb_updated_nets(iter_results.bb_updated_nets);
454	
455	        if (itry >= high_effort_congestion_mode_iteration_threshold) {
456	            //We are approaching the maximum number of routing iterations,
457	            //and still do not have a legal routing. Switch to a mode which
458	            //focuses more on attempting to resolve routing conflicts.
459	            router_congestion_mode = RouterCongestionMode::CONFLICTED;
460	        }
461	
462	        //Update pres_fac
463	        if (itry == 1) {
464	            pres_fac = router_opts.initial_pres_fac;
465	            update_draw_pres_fac(pres_fac);
466	        } else {
467	            pres_fac *= router_opts.pres_fac_mult;
468	            pres_fac = std::min(pres_fac, router_opts.max_pres_fac);
469	            /* Set the maximum pres_fac to the value passed by the command line argument */
470	            update_draw_pres_fac(pres_fac);
471	
472	            // Increase short path criticality if it's having a hard time resolving hold violations due to congestion
473	            if (budgeting_inf.if_set()) {
474	                bool rcv_finished = false;
475	
476	                /* This constant represents how much extra delay the budget increaser adds to the minimum and maximum delay budgets
477	                 * Experimentally this value delivers fast hold slack resolution, while not overwhelming the router
478	                 * Increasing this will make it resolve hold faster, but could result in lower circuit quality */
479	                constexpr float budget_increase_factor = 300e-12;
480	
481	                if (itry > 5 && worst_negative_slack != 0)
482	                    rcv_finished = budgeting_inf.increase_min_budgets_if_struggling(budget_increase_factor, timing_info, worst_negative_slack, netlist_pin_lookup);
483	                if (rcv_finished)
484	                    rcv_finished_count--;
485	                else
486	                    rcv_finished_count = RCV_FINISH_EARLY_COUNTDOWN;
487	            }
488	        }
489	
490	        if (router_congestion_mode == RouterCongestionMode::CONFLICTED) {
491	            //The design appears to have routing conflicts which are difficult to resolve:
492	            //  1) Don't re-route legal connections due to delay. This allows
493	            //     the router to focus on the actual conflicts
494	            //  2) Increase the net bounding boxes. This potentially allows
495	            //     the router to route around otherwise congested regions
496	            //     (at the cost of high run-time).
497	
498	            //Increase the size of the net bounding boxes to give the router more
499	            //freedom to find alternate paths.
500	            //
501	            //In the case of routing conflicts there are multiple connections competing
502	            //for the same resources which can not resolve the congestion themselves.
503	            //In normal routing mode we try to keep the bounding boxes small to minimize
504	            //run-time, but this can limits how far signals can detour (i.e. they can't
505	            //route outside the bounding box), which can cause conflicts to oscillate back
506	            //and forth without resolving.
507	            //
508	            //By scaling the bounding boxes here, we slowly increase the router's search
509	            //space in hopes of it allowing signals to move further out of the way to
510	            //alleviate the conflicts.
511	            if (itry_conflicted_mode % BB_SCALE_ITER_COUNT == 0) {
512	                //We scale the bounding boxes by BB_SCALE_FACTOR,
513	                //every BB_SCALE_ITER_COUNT iterations. This ensures
514	                //that we give the router some time (BB_SCALE_ITER_COUNT) to try
515	                //resolve/negotiate congestion at the new BB factor.
516	                //
517	                //Note that we increase the BB factor slowly to try and minimize
518	                //the bounding box size (since larger bounding boxes slow the router down).
519	                auto& grid = g_vpr_ctx.device().grid;
520	                int max_grid_dim = std::max(grid.width(), grid.height());
521	
522	                //Scale by BB_SCALE_FACTOR but clip to grid size to avoid overflow
523	                bb_fac = std::min<int>(max_grid_dim, bb_fac * BB_SCALE_FACTOR);
524	
525	                route_ctx.route_bb = load_route_bb(net_list, bb_fac);
526	            }
527	
528	            ++itry_conflicted_mode;
529	        }
530	
531	        if (router_opts.with_timing_analysis) {
532	            if (itry == 1) {
533	                // first iteration sets up the lower bound connection delays since only timing is optimized for
534	                connections_inf.set_stable_critical_path_delay(critical_path.delay());
535	                connections_inf.set_lower_bound_connection_delays(net_delay);
536	
537	                //load budgets using information from uncongested delay information
538	                budgeting_inf.load_route_budgets(net_delay, timing_info, netlist_pin_lookup, router_opts);
539	
540	                if (router_opts.routing_budgets_algorithm == YOYO)
541	                    netlist_router->set_rcv_enabled(true);
542	            } else {
543	                bool stable_routing_configuration = true;
544	
545	                /*
546	                 * Determine if any connection need to be forcibly re-routed due to timing
547	                 */
548	
549	                //Yes, if explicitly enabled
550	                bool should_ripup_for_delay = (router_opts.incr_reroute_delay_ripup == e_incr_reroute_delay_ripup::ON);
551	
552	                //Or, if things are not too congested
553	                should_ripup_for_delay |= (router_opts.incr_reroute_delay_ripup == e_incr_reroute_delay_ripup::AUTO
554	                                           && router_congestion_mode == RouterCongestionMode::NORMAL);
555	
556	                if (should_ripup_for_delay) {
557	                    if (connections_inf.critical_path_delay_grew_significantly(critical_path.delay())) {
558	                        // only need to forcibly reroute if critical path grew significantly
559	                        stable_routing_configuration = connections_inf.forcibly_reroute_connections(router_opts.max_criticality,
560	                                                                                                    timing_info,
561	                                                                                                    netlist_pin_lookup,
562	                                                                                                    net_delay);
563	                    }
564	                }
565	
566	                // not stable if any connection needs to be forcibly rerouted
567	                if (stable_routing_configuration) {
568	                    connections_inf.set_stable_critical_path_delay(critical_path.delay());
569	                }
570	            }
571	        } else {
572	            /* If timing analysis is not enabled, make sure that the criticalities and the
573	             * net_delays stay as 0 so that wirelength can be optimized. */
574	
575	            for (auto net_id : net_list.nets()) {
576	                for (unsigned int ipin = 1; ipin < net_list.net_pins(net_id).size(); ++ipin) {
577	                    net_delay[net_id][ipin] = 0.;
578	                }
579	            }
580	        }
581	
582	        if (router_opts.congestion_analysis) profiling::congestion_analysis();
583	        if (router_opts.fanout_analysis) profiling::time_on_fanout_analysis();
584	        // profiling::time_on_criticality_analysis();
585	    }
586	
587	    /* Write out partition tree logs (no-op if debug option not set) */
588	    PartitionTreeDebug::write("partition_tree.log");
589	
590	    if (success) {
591	        VTR_LOG("Restoring best routing\n");
592	
593	        auto& router_ctx = g_vpr_ctx.mutable_routing();
594	
595	        /* Restore congestion from best route */
596	        for (auto net_id : net_list.nets()) {
597	            if (route_ctx.route_trees[net_id])
598	                pathfinder_update_cost_from_route_tree(route_ctx.route_trees[net_id]->root(), -1);
599	            if (best_routing[net_id])
600	                pathfinder_update_cost_from_route_tree(best_routing[net_id]->root(), 1);
601	        }
602	        router_ctx.route_trees = best_routing;
603	        router_ctx.clb_opins_used_locally = best_clb_opins_used_locally;
604	
605	        prune_unused_non_configurable_nets(connections_inf, net_list);
606	
607	        if (router_opts.with_timing_analysis) {
608	            VTR_LOG("Critical path: %g ns\n", 1e9 * best_routing_metrics.critical_path.delay());
609	        }
610	
611	        VTR_LOG("Successfully routed after %d routing iterations.\n", itry);
612	    } else {
613	        VTR_LOG("Routing failed.\n");
614	
615	        //If the routing fails, print the overused info
616	        print_overused_nodes_status(router_opts, overuse_info);
617	
618	        if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
619	            if (f_router_debug) {
620	                print_invalid_routing_info(net_list, is_flat);
621	            }
622	        }
623	    }
624	
625	    if (router_opts.with_timing_analysis) {
626	        VTR_LOG("Final Net Connection Criticality Histogram:\n");
627	        print_router_criticality_histogram(net_list, *timing_info, netlist_pin_lookup, is_flat);
628	    }
629	
630	    VTR_ASSERT(router_stats.heap_pushes >= router_stats.intra_cluster_node_pushes);
631	    VTR_ASSERT(router_stats.heap_pops >= router_stats.intra_cluster_node_pops);
632	    VTR_LOG(
633	        "Router Stats: total_nets_routed: %zu total_connections_routed: %zu total_heap_pushes: %zu total_heap_pops: %zu ",
634	        router_stats.nets_routed, router_stats.connections_routed, router_stats.heap_pushes, router_stats.heap_pops);
635	    if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
636	        VTR_LOG(
637	            "total_internal_heap_pushes: %zu total_internal_heap_pops: %zu total_external_heap_pushes: %zu total_external_heap_pops: %zu ",
638	            router_stats.intra_cluster_node_pushes, router_stats.intra_cluster_node_pops,
639	            router_stats.inter_cluster_node_pushes, router_stats.inter_cluster_node_pops);
640	
641	        for (e_rr_type rr_type : RR_TYPES) {
642	            VTR_LOG("total_external_%s_pushes: %zu ", rr_node_typename[rr_type], router_stats.inter_cluster_node_type_cnt_pushes[rr_type]);
643	            VTR_LOG("total_external_%s_pops: %zu ", rr_node_typename[rr_type], router_stats.inter_cluster_node_type_cnt_pops[rr_type]);
644	            VTR_LOG("total_internal_%s_pushes: %zu ", rr_node_typename[rr_type], router_stats.intra_cluster_node_type_cnt_pushes[rr_type]);
645	            VTR_LOG("total_internal_%s_pops: %zu ", rr_node_typename[rr_type], router_stats.intra_cluster_node_type_cnt_pops[rr_type]);
646	            VTR_LOG("rt_node_%s_pushes: %zu ", rr_node_typename[rr_type], router_stats.rt_node_pushes[rr_type]);
647	        }
648	    }
649	    VTR_LOG("\n");
650	
651	    return success;
652	}
