20	/** Attempt to route a single net.
21	 *
22	 * @param router The ConnectionRouterType instance
23	 * @param net_list Input netlist
24	 * @param net_id
25	 * @param itry # of iteration
26	 * @param pres_fac
27	 * @param router_opts
28	 * @param connections_inf
29	 * @param router_stats
30	 * @param pin_criticality
31	 * @param rt_node_of_sink Lookup from target_pin-like indices (indicating SINK nodes) to RouteTreeNodes
32	 * @param net_delay
33	 * @param netlist_pin_lookup
34	 * @param timing_info
35	 * @param pin_timing_invalidator
36	 * @param budgeting_inf
37	 * @param worst_neg_slack
38	 * @param routing_predictor
39	 * @param choking_spots
40	 * @param is_flat
41	 * @param net_bb Bounding box for the net (Routing resources outside net_bb will not be used)
42	 * @param should_setup Should we reset/prune the existing route tree first?
43	 * @param sink_mask Which sinks to route? Assumed all sinks if nullopt, otherwise a mask of [1..num_sinks+1] where set bits request the sink to be routed
44	 * @return NetResultFlags for this net */
45	template<typename ConnectionRouterType>
46	inline NetResultFlags route_net(ConnectionRouterType& router,
47	                                const Netlist<>& net_list,
48	                                const ParentNetId& net_id,
49	                                int itry,
50	                                float pres_fac,
51	                                const t_router_opts& router_opts,
52	                                CBRR& connections_inf,
53	                                RouterStats& router_stats,
54	                                NetPinsMatrix<float>& net_delays,
55	                                const ClusteredPinAtomPinsLookup& netlist_pin_lookup,
56	                                SetupHoldTimingInfo* timing_info,
57	                                NetPinTimingInvalidator* pin_timing_invalidator,
58	                                route_budgets& budgeting_inf,
59	                                float worst_negative_slack,
60	                                const RoutingPredictor& routing_predictor,
61	                                const std::vector<std::unordered_map<RRNodeId, int>>& choking_spots,
62	                                bool is_flat,
63	                                const t_bb& net_bb,
64	                                bool should_setup = true,
65	                                vtr::optional<const vtr::dynamic_bitset<>&> sink_mask = vtr::nullopt) {
66	    auto& route_ctx = g_vpr_ctx.mutable_routing();
67	
68	    NetResultFlags flags;
69	    flags.success = true;
70	
71	    if (!should_route_net(net_list, net_id, connections_inf, budgeting_inf, worst_negative_slack, true))
72	        return flags;
73	
74	    // track time spent vs fanout
75	    profiling::net_fanout_start();
76	
77	    flags.was_rerouted = true; // Flag to record whether routing was actually changed
78	
79	    auto& device_ctx = g_vpr_ctx.device();
80	    const auto& rr_graph = device_ctx.rr_graph;
81	
82	    unsigned int num_sinks = net_list.net_sinks(net_id).size();
83	
84	    VTR_LOGV_DEBUG(f_router_debug, "Routing Net %zu (%zu sinks)\n", size_t(net_id), num_sinks);
85	
86	    /* Prune or rip-up existing routing for the net */
87	    if (should_setup) {
88	        setup_net(
89	            itry,
90	            net_id,
91	            net_list,
92	            connections_inf,
93	            router_opts,
94	            worst_negative_slack);
95	    }
96	
97	    VTR_ASSERT(route_ctx.route_trees[net_id]);
98	    RouteTree& tree = route_ctx.route_trees[net_id].value();
99	
100	    bool high_fanout = is_high_fanout(num_sinks, router_opts.high_fanout_threshold);
101	
102	    SpatialRouteTreeLookup spatial_route_tree_lookup;
103	    if (high_fanout) {
104	        spatial_route_tree_lookup = build_route_tree_spatial_lookup(net_list,
105	                                                                    route_ctx.route_bb,
106	                                                                    net_id,
107	                                                                    tree.root());
108	    }
109	
110	    /* 1-indexed! */
111	    std::vector<float> pin_criticality(tree.num_sinks() + 1, 0);
112	
113	    // after this point the route tree is correct
114	    // remaining_targets from this point on are the **pin indices** that have yet to be routed
115	    auto remaining_targets_mask = ~tree.get_is_isink_reached();
116	    if (sink_mask)
117	        remaining_targets_mask &= sink_mask.value();
118	
119	    auto remaining_targets = sink_mask_to_vector(remaining_targets_mask, num_sinks);
120	
121	    // calculate criticality of remaining target pins
122	    for (int ipin : remaining_targets) {
123	        auto pin = net_list.net_pin(net_id, ipin);
124	        pin_criticality[ipin] = get_net_pin_criticality(timing_info,
125	                                                        netlist_pin_lookup,
126	                                                        router_opts.max_criticality,
127	                                                        router_opts.criticality_exp,
128	                                                        net_id,
129	                                                        pin,
130	                                                        is_flat);
131	    }
132	
133	    // compare the criticality of different sink nodes
134	    std::stable_sort(begin(remaining_targets), end(remaining_targets), [&](int a, int b) {
135	        return pin_criticality[a] > pin_criticality[b];
136	    });
137	
138	    /* Update base costs according to fanout and criticality rules */
139	    update_rr_base_costs(num_sinks);
140	
141	    t_conn_delay_budget conn_delay_budget;
142	    t_conn_cost_params cost_params;
143	    cost_params.astar_fac = router_opts.astar_fac;
144	    cost_params.astar_offset = router_opts.astar_offset;
145	    cost_params.post_target_prune_fac = router_opts.post_target_prune_fac;
146	    cost_params.post_target_prune_offset = router_opts.post_target_prune_offset;
147	    cost_params.bend_cost = router_opts.bend_cost;
148	    cost_params.pres_fac = pres_fac;
149	    cost_params.delay_budget = ((budgeting_inf.if_set()) ? &conn_delay_budget : nullptr);
150	
151	    // Pre-route to clock source for clock nets (marked as global nets)
152	    if (net_list.net_is_global(net_id) && router_opts.two_stage_clock_routing) {
153	        auto& route_constraints = route_ctx.constraints;
154	        std::string net_name = net_list.net_name(net_id);
155	
156	        // If there is no routing constraint for the current global net
157	        // and the clock modelling is set to dedicated network or
158	        //there is a routing constraint for the current net setting routing model
159	        // to the dedicated network run the first stage router.
160	        if ((!route_constraints.has_routing_constraint(net_name) && router_opts.clock_modeling == e_clock_modeling::DEDICATED_NETWORK)
161	            || route_constraints.get_route_model_by_net_name(net_name) == e_clock_modeling::DEDICATED_NETWORK) {
162	            std::string clock_network_name = "";
163	
164	            // If a user-specified routing constraints exists for the current net get the clock network name
165	            // from the constraints file, otherwise use the default clock network name
166	            if (route_constraints.has_routing_constraint(net_name)) {
167	                clock_network_name = route_constraints.get_routing_network_name_by_net_name(net_name);
168	            } else {
169	                auto& arch = device_ctx.arch;
170	                clock_network_name = arch->default_clock_network_name;
171	            }
172	
173	            RRNodeId sink_node = rr_graph.virtual_clock_network_root_idx(clock_network_name.c_str());
174	
175	            enable_router_debug(router_opts, net_id, sink_node, itry, &router);
176	
177	            VTR_LOGV_DEBUG(f_router_debug, "Pre-routing global net %zu\n", size_t(net_id));
178	
179	            // Set to the max timing criticality which should intern minimize clock insertion
180	            // delay by selecting a direct route from the clock source to the virtual sink
181	            cost_params.criticality = router_opts.max_criticality;
182	
183	            if (sink_node == RRNodeId::INVALID()) {
184	                VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Cannot route net \"%s\" through given clock network. Unknown clock network name \"%s\"", net_name.c_str(), clock_network_name.c_str());
185	            }
186	
187	            flags = pre_route_to_clock_root(router,
188	                                            net_id,
189	                                            net_list,
190	                                            sink_node,
191	                                            cost_params,
192	                                            router_opts.high_fanout_threshold,
193	                                            tree,
194	                                            spatial_route_tree_lookup,
195	                                            router_stats,
196	                                            is_flat);
197	
198	            if (flags.success == false)
199	                return flags;
200	        }
201	    }
202	
203	    if (budgeting_inf.if_set()) {
204	        budgeting_inf.set_should_reroute(net_id, false);
205	    }
206	
207	    // explore in order of decreasing criticality (no longer need sink_order array)
208	    for (unsigned itarget = 0; itarget < remaining_targets.size(); ++itarget) {
209	        int target_pin = remaining_targets[itarget];
210	
211	        RRNodeId sink_rr = route_ctx.net_rr_terminals[net_id][target_pin];
212	
213	        enable_router_debug(router_opts, net_id, sink_rr, itry, &router);
214	
215	        cost_params.criticality = pin_criticality[target_pin];
216	
217	        if (budgeting_inf.if_set()) {
218	            conn_delay_budget.max_delay = budgeting_inf.get_max_delay_budget(net_id, target_pin);
219	            conn_delay_budget.target_delay = budgeting_inf.get_delay_target(net_id, target_pin);
220	            conn_delay_budget.min_delay = budgeting_inf.get_min_delay_budget(net_id, target_pin);
221	            conn_delay_budget.short_path_criticality = budgeting_inf.get_crit_short_path(net_id, target_pin);
222	            conn_delay_budget.routing_budgets_algorithm = router_opts.routing_budgets_algorithm;
223	        }
224	
225	        profiling::conn_start();
226	
227	        // build a branch in the route tree to the target
228	        auto sink_flags = route_sink(router,
229	                                     net_list,
230	                                     net_id,
231	                                     itarget,
232	                                     target_pin,
233	                                     cost_params,
234	                                     router_opts,
235	                                     tree,
236	                                     spatial_route_tree_lookup,
237	                                     router_stats,
238	                                     budgeting_inf,
239	                                     routing_predictor,
240	                                     choking_spots,
241	                                     is_flat,
242	                                     net_bb);
243	
244	        flags.retry_with_full_bb |= sink_flags.retry_with_full_bb;
245	
246	        if (!sink_flags.success) {
247	            flags.success = false;
248	            VTR_LOG("Routing failed for sink %d of net %d\n", target_pin, net_id);
249	            return flags;
250	        }
251	
252	        profiling::conn_finish(size_t(route_ctx.net_rr_terminals[net_id][0]),
253	                               size_t(sink_rr),
254	                               pin_criticality[target_pin]);
255	
256	        ++router_stats.connections_routed;
257	    } // finished all sinks
258	
259	    ++router_stats.nets_routed;
260	    profiling::net_finish();
261	
262	    /* For later timing analysis. */
263	
264	    float* net_delay = net_delays[net_id].data();
265	
266	    // may have to update timing delay of the previously legally reached sinks since downstream capacitance could be changed
267	    update_net_delays_from_route_tree(net_delay,
268	                                      net_list,
269	                                      net_id,
270	                                      timing_info,
271	                                      pin_timing_invalidator);
272	
273	    if (router_opts.update_lower_bound_delays) {
274	        for (int ipin : remaining_targets) {
275	            connections_inf.update_lower_bound_connection_delay(net_id, ipin, net_delay[ipin]);
276	        }
277	    }
278	
279	    VTR_ASSERT_MSG(g_vpr_ctx.routing().rr_node_route_inf[tree.root().inode].occ() <= rr_graph.node_capacity(tree.root().inode), "SOURCE should never be congested");
280	    VTR_LOGV_DEBUG(f_router_debug, "Routed Net %zu (%zu sinks)\n", size_t(net_id), num_sinks);
281	
282	    router.empty_rcv_route_tree_set(); // ?
283	
284	    profiling::net_fanout_end(net_list.net_sinks(net_id).size());
285	
286	    route_ctx.net_status.set_is_routed(net_id, true);
287	    return flags;
288	}
289	
290	/** Route to a "virtual sink" in the netlist which corresponds to the start point
291	 * of the global clock network. */
292	template<typename ConnectionRouterType>
293	inline NetResultFlags pre_route_to_clock_root(ConnectionRouterType& router,
294	                                              ParentNetId net_id,
295	                                              const Netlist<>& net_list,
296	                                              RRNodeId sink_node,
297	                                              const t_conn_cost_params cost_params,
298	                                              int high_fanout_threshold,
299	                                              RouteTree& tree,
300	                                              SpatialRouteTreeLookup& spatial_rt_lookup,
301	                                              RouterStats& router_stats,
302	                                              bool is_flat) {
303	    const auto& device_ctx = g_vpr_ctx.device();
304	    auto& route_ctx = g_vpr_ctx.mutable_routing();
305	    auto& m_route_ctx = g_vpr_ctx.mutable_routing();
306	
307	    NetResultFlags out;
308	    out.was_rerouted = true;
309	
310	    bool high_fanout = is_high_fanout(net_list.net_sinks(net_id).size(), high_fanout_threshold);
311	
312	    VTR_LOGV_DEBUG(f_router_debug, "Net %zu pre-route to (%s)\n", size_t(net_id), describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, sink_node, is_flat).c_str());
313	    profiling::sink_criticality_start();
314	
315	    t_bb bounding_box = route_ctx.route_bb[net_id];
316	
317	    router.clear_modified_rr_node_info();
318	
319	    bool found_path, retry_with_full_bb;
320	    RTExploredNode cheapest;
321	    ConnectionParameters conn_params(net_id,
322	                                     -1,
323	                                     false,
324	                                     std::unordered_map<RRNodeId, int>());
325	
326	    std::tie(found_path, retry_with_full_bb, cheapest) = router.timing_driven_route_connection_from_route_tree(
327	        tree.root(),
328	        sink_node,
329	        cost_params,
330	        bounding_box,
331	        router_stats,
332	        conn_params);
333	
334	    // TODO: Parts of the rest of this function are repetitive to code in route_sink. Should refactor.
335	    if (!found_path) {
336	        ParentBlockId src_block = net_list.net_driver_block(net_id);
337	        VTR_LOG("Failed to route connection from '%s' to '%s' for net '%s' (#%zu)\n",
338	                net_list.block_name(src_block).c_str(),
339	                describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, sink_node, is_flat).c_str(),
340	                net_list.net_name(net_id).c_str(),
341	                size_t(net_id));
342	        if (f_router_debug) {
343	            update_screen(ScreenUpdatePriority::MAJOR, "Unable to route connection.", e_pic_type::ROUTING, nullptr);
344	        }
345	        router.reset_path_costs();
346	        out.success = false;
347	        out.retry_with_full_bb = retry_with_full_bb;
348	        return out;
349	    }
350	
351	    profiling::sink_criticality_end(cost_params.criticality);
352	
353	    /* This is a special pre-route to a sink that does not correspond to any    *
354	     * netlist pin, but which can be reached from the global clock root drive   *
355	     * points. Therefore, we can set the net pin index of the sink node to      *
356	     * UNDEFINED (meaning illegal) as it is not meaningful for this sink.            */
357	    vtr::optional<const RouteTreeNode&> new_branch, new_sink;
358	    std::tie(new_branch, new_sink) = tree.update_from_heap(&cheapest, UNDEFINED, ((high_fanout) ? &spatial_rt_lookup : nullptr), is_flat);
359	
360	    VTR_ASSERT_DEBUG(!high_fanout || validate_route_tree_spatial_lookup(tree.root(), spatial_rt_lookup));
361	
362	    if (f_router_debug) {
363	        std::string msg = vtr::string_fmt("Routed Net %zu connection to RR node %d successfully", size_t(net_id), sink_node);
364	        update_screen(ScreenUpdatePriority::MAJOR, msg.c_str(), e_pic_type::ROUTING, nullptr);
365	    }
366	
367	    if (new_branch)
368	        pathfinder_update_cost_from_route_tree(new_branch.value(), 1);
369	
370	    // need to guarantee ALL nodes' path costs are HUGE_POSITIVE_FLOAT at the start of routing to a sink
371	    // do this by resetting all the path_costs that have been touched while routing to the current sink
372	    router.reset_path_costs();
373	
374	    // Post route cleanup:
375	    // - remove sink from route tree and fix routing for all nodes leading to the sink ("freeze")
376	    // - free up virtual sink occupancy
377	    tree.freeze();
378	    m_route_ctx.rr_node_route_inf[sink_node].set_occ(0);
379	
380	    // routed to a sink successfully
381	    out.success = true;
382	    return out;
383	}
384	
385	/** Attempt to route a single sink (target_pin) in a net.
386	 * In the process, update global pathfinder costs, rr_node_route_inf and extend the global RouteTree
387	 * for this net.
388	 *
389	 * @param router The ConnectionRouterType instance
390	 * @param net_list Input netlist
391	 * @param net_id
392	 * @param itarget # of this connection in the net (only used for debug output)
393	 * @param target_pin # of this sink in the net (TODO: is it the same thing as itarget?)
394	 * @param cost_params
395	 * @param router_opts
396	 * @param[in, out] tree RouteTree describing the current routing state
397	 * @param rt_node_of_sink Lookup from target_pin-like indices (indicating SINK nodes) to RouteTreeNodes
398	 * @param spatial_rt_lookup
399	 * @param router_stats
400	 * @param budgeting_inf
401	 * @param routing_predictor
402	 * @param choking_spots
403	 * @param is_flat
404	 * @param net_bb Bounding box for the net (Routing resources outside net_bb will not be used)
405	 * @return NetResultFlags for this sink to be bubbled up through route_net */
406	template<typename ConnectionRouterType>
407	inline NetResultFlags route_sink(ConnectionRouterType& router,
408	                                 const Netlist<>& net_list,
409	                                 ParentNetId net_id,
410	                                 unsigned itarget,
411	                                 int target_pin,
412	                                 const t_conn_cost_params cost_params,
413	                                 const t_router_opts& router_opts,
414	                                 RouteTree& tree,
415	                                 SpatialRouteTreeLookup& spatial_rt_lookup,
416	                                 RouterStats& router_stats,
417	                                 route_budgets& budgeting_inf,
418	                                 const RoutingPredictor& routing_predictor,
419	                                 const std::vector<std::unordered_map<RRNodeId, int>>& choking_spots,
420	                                 bool is_flat,
421	                                 const t_bb& net_bb) {
422	    const auto& device_ctx = g_vpr_ctx.device();
423	    auto& route_ctx = g_vpr_ctx.mutable_routing();
424	
425	    NetResultFlags flags;
426	
427	    profiling::sink_criticality_start();
428	
429	    RRNodeId sink_node = route_ctx.net_rr_terminals[net_id][target_pin];
430	    VTR_LOGV_DEBUG(f_router_debug, "Net %zu Target %d (%s)\n", size_t(net_id), itarget, describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, sink_node, is_flat).c_str());
431	
432	    router.clear_modified_rr_node_info();
433	
434	    bool found_path;
435	    RTExploredNode cheapest;
436	
437	    bool net_is_global = net_list.net_is_global(net_id);
438	    bool high_fanout = is_high_fanout(net_list.net_sinks(net_id).size(), router_opts.high_fanout_threshold);
439	    constexpr float HIGH_FANOUT_CRITICALITY_THRESHOLD = 0.9;
440	    bool sink_critical = (cost_params.criticality > HIGH_FANOUT_CRITICALITY_THRESHOLD);
441	    bool net_is_clock = route_ctx.is_clock_net[net_id] != 0;
442	
443	    bool router_opt_choke_points = ((int)choking_spots[target_pin].size() != 0) && router_opts.has_choke_point;
444	    ConnectionParameters conn_params(net_id, target_pin, router_opt_choke_points, choking_spots[target_pin]);
445	
446	    //We normally route high fanout nets by only adding spatially close-by routing to the heap (reduces run-time).
447	    //However, if the current sink is 'critical' from a timing perspective, we put the entire route tree back onto
448	    //the heap to ensure it has more flexibility to find the best path.
449	    if (high_fanout && !sink_critical && !net_is_global && !net_is_clock && -routing_predictor.get_slope() > router_opts.high_fanout_max_slope) {
450	        std::tie(found_path, flags.retry_with_full_bb, cheapest) = router.timing_driven_route_connection_from_route_tree_high_fanout(tree.root(),
451	                                                                                                                                     sink_node,
452	                                                                                                                                     cost_params,
453	                                                                                                                                     net_bb,
454	                                                                                                                                     spatial_rt_lookup,
455	                                                                                                                                     router_stats,
456	                                                                                                                                     conn_params);
457	    } else {
458	        std::tie(found_path, flags.retry_with_full_bb, cheapest) = router.timing_driven_route_connection_from_route_tree(tree.root(),
459	                                                                                                                         sink_node,
460	                                                                                                                         cost_params,
461	                                                                                                                         net_bb,
462	                                                                                                                         router_stats,
463	                                                                                                                         conn_params);
464	    }
465	
466	    if (!found_path) {
467	        ParentBlockId src_block = net_list.net_driver_block(net_id);
468	        ParentBlockId sink_block = net_list.pin_block(*(net_list.net_pins(net_id).begin() + target_pin));
469	        VTR_LOG("Failed to route connection from '%s' to '%s' for net '%s' (#%zu)\n",
470	                net_list.block_name(src_block).c_str(),
471	                net_list.block_name(sink_block).c_str(),
472	                net_list.net_name(net_id).c_str(),
473	                size_t(net_id));
474	        if (f_router_debug) {
475	            update_screen(ScreenUpdatePriority::MAJOR, "Unable to route connection.", e_pic_type::ROUTING, nullptr);
476	        }
477	        flags.success = false;
478	        router.reset_path_costs();
479	        return flags;
480	    }
481	
482	    profiling::sink_criticality_end(cost_params.criticality);
483	
484	    vtr::optional<const RouteTreeNode&> new_branch, new_sink;
485	    std::tie(new_branch, new_sink) = tree.update_from_heap(&cheapest, target_pin, ((high_fanout) ? &spatial_rt_lookup : nullptr), is_flat);
486	
487	    VTR_ASSERT_DEBUG(!high_fanout || validate_route_tree_spatial_lookup(tree.root(), spatial_rt_lookup));
488	
489	    if (f_router_debug) {
490	        std::string msg = vtr::string_fmt("Routed Net %zu connection %d to RR node %d successfully", size_t(net_id), itarget, sink_node);
491	        update_screen(ScreenUpdatePriority::MAJOR, msg.c_str(), e_pic_type::ROUTING, nullptr);
492	    }
493	
494	    if (budgeting_inf.if_set() && cheapest.rcv_path_backward_delay != std::numeric_limits<float>::infinity() && cost_params.delay_budget) {
495	        if (cheapest.rcv_path_backward_delay < cost_params.delay_budget->min_delay) {
496	            budgeting_inf.set_should_reroute(net_id, true);
497	        }
498	    }
499	
500	    /* update global occupancy from the new branch */
501	    if (new_branch)
502	        pathfinder_update_cost_from_route_tree(new_branch.value(), 1);
503	
504	    // need to guarantee ALL nodes' path costs are HUGE_POSITIVE_FLOAT at the start of routing to a sink
505	    // do this by resetting all the path_costs that have been touched while routing to the current sink
506	    router.reset_path_costs();
507	
508	    // routed to a sink successfully
509	    flags.success = true;
510	    return flags;
511	}
