128	                      CBRR& connections_inf,
129	                      route_budgets& budgeting_inf,
130	                      float worst_negative_slack,
131	                      bool if_force_reroute) {
132	    auto& route_ctx = g_vpr_ctx.routing();
133	    auto& device_ctx = g_vpr_ctx.device();
134	    const auto& rr_graph = device_ctx.rr_graph;
135	
136	    if (route_ctx.net_status.is_fixed(net_id)) /* Skip pre-routed nets */
137	        return false;
138	    if (net_list.net_is_ignored(net_id)) /* Skip ignored nets */
139	        return false;
140	
141	    if (!route_ctx.route_trees[net_id]) /* No routing yet */
142	        return true;
143	    if (worst_negative_slack != 0 && budgeting_inf.if_set() && budgeting_inf.get_should_reroute(net_id)) /* Reroute for hold */
144	        return true;
145	
146	    const RouteTree& tree = route_ctx.route_trees[net_id].value();
147	
148	    /* Walk over all rt_nodes in the net */
149	    for (auto& rt_node : tree.all_nodes()) {
150	        RRNodeId inode = rt_node.inode;
151	        int occ = route_ctx.rr_node_route_inf[inode].occ();
152	        int capacity = rr_graph.node_capacity(inode);
153	
154	        if (occ > capacity) {
155	            return true; /* overuse detected */
156	        }
157	
158	        if (rt_node.is_leaf()) { //End of a branch
159	            // even if net is fully routed, not complete if parts of it should get ripped up (EXPERIMENTAL)
160	            if (if_force_reroute) {
161	                if (connections_inf.should_force_reroute_connection(net_id, inode)) {
162	                    return true;
163	                }
164	            }
165	        }
166	    }
167	
168	    /* If all sinks have been routed to without overuse, no need to route this */
169	    if (tree.get_remaining_isinks().empty())
170	        return false;
171	
172	    return true;
173	}
