        VTR_ASSERT(!rr_graph.edge_is_configurable(rr_node, iedge));
        RRNodeId to_rr_node = rr_graph.edge_sink_node(rr_node, iedge);

        if (_rr_node_to_rt_node.contains(to_rr_node)) // TODO: not 100% sure about this
