        RouteTreeNode* new_node = new RouteTreeNode(to_rr_node, edge_switch, rt_node);
        add_node(rt_node, new_node);

        new_node->net_pin_index = UNDEFINED;
        if (rr_graph.node_type(to_rr_node) == e_rr_type::IPIN && !is_flat) {
