71	bool Connection_based_routing_resources::forcibly_reroute_connections(float max_criticality,
72	                                                                      std::shared_ptr<const SetupTimingInfo> timing_info,
73	                                                                      const ClusteredPinAtomPinsLookup& netlist_pin_lookup,
74	                                                                      NetPinsMatrix<float>& net_delay) {
75	    bool any_connection_rerouted = false; // true if any connection has been marked for rerouting
76	
77	    for (auto net_id : net_list_.nets()) {
78	        for (auto pin_id : net_list_.net_sinks(net_id)) {
79	            int ipin = net_list_.pin_net_index(pin_id);
80	
81	            // rr sink node index corresponding to this connection terminal
82	            auto rr_sink_node = net_terminals_[net_id][ipin];
