88	            if (lower_bound_connection_delay[net_id][ipin - 1] == 0)
89	                continue;
90	
91	            // update if more optimal connection found
92	            if (net_delay[net_id][ipin] < lower_bound_connection_delay[net_id][ipin - 1]) {
93	                lower_bound_connection_delay[net_id][ipin - 1] = net_delay[net_id][ipin];
94	                continue;
95	            }
96	
97	            // skip if connection criticality is too low (not a problem connection)
98	            //#TODO: Check pin_id
99	            float pin_criticality = calculate_clb_net_pin_criticality(*timing_info, netlist_pin_lookup, pin_id, is_flat_);
100	            if (pin_criticality < (max_criticality * connection_criticality_tolerance))
101	                continue;
102	
103	            // skip if connection's delay is close to optimal
104	            if (net_delay[net_id][ipin] < (lower_bound_connection_delay[net_id][ipin - 1] * connection_delay_optimality_tolerance))
105	                continue;
106	
107	            forcible_reroute_connection_flag[net_id][rr_sink_node] = true;
108	            // note that we don't set forcible_reroute_connection_flag to false when the converse is true
109	            // resetting back to false will be done during tree pruning, after the sink has been legally reached [!]
110	            any_connection_rerouted = true;
111	
112	            profiling::mark_for_forced_reroute();
113	        }
114	    }
115	
116	    // non-stable configuration if any connection has to be rerouted, otherwise stable
117	    return !any_connection_rerouted;
